div.p:
memory_array: "Physical Memory Address Space (Contiguous Array)" {
style: {
stroke: "#333333"
stroke-width: 2
fill: "#FFFFFF"
}

pre.code:
header: "Top Subtree Header (Root)" {
  style.fill: "#D1C4E9"
  label: "vEB Root Metadata [0x00 - 0x3F] (64B)"
}

nodes: "Top Subtree Nodes (L0 to L(H/2-1))" {
  style.fill: "#BBDEFB"
  label: "Node Data √N [0x40 - 0x7F] (64B)"
}

header -> nodes: "Implicit Address Offset" {
  style.stroke: "#FF9800"
}

div.p:
boundary_128: "--- SUBTREE BOUNDARY (128B) ---" {
style: {
stroke: "#9E9E9E"
stroke-dash: 5
stroke-width: 2
font-color: "#757575"
}
}

bottom_subtrees: "Bottom Subtree Region (Level H/2 to Leaf)" {
style: {
fill: "#F5F5F5"
stroke: "#757575"
stroke-dash: 2
}

pre.code:
grid-columns: 2
grid-gap: 15

bs0: "Cluster B0" {
  style.fill: "#BBDEFB"
  style.stroke: "#2196F3"
  label: "B0: Nodes [0x80-0xBF]\nSize: 64B (1 CL)"
}
bs1: "Cluster B1" {
  style.fill: "#BBDEFB"
  style.stroke: "#2196F3"
  label: "B1: Nodes [0xC0-0xFF]\nSize: 64B (1 CL)"
}
bs2: "Cluster B2" {
  style.fill: "#BBDEFB"
  style.stroke: "#2196F3"
  label: "B2: Nodes [0x100-0x13F]\nSize: 64B (1 CL)"
}
bs3: "Cluster B3" {
  style.fill: "#BBDEFB"
  style.stroke: "#2196F3"
  label: "B3: Nodes [0x140-0x17F]\nSize: 64B (1 CL)"
}
bs_more: "..." {
  shape: text
  style.font-size: 30
}
bsn: "Cluster B√N-1" {
  style.fill: "#BBDEFB"
  style.stroke: "#2196F3"
  label: "B_last: Leaf Cluster\nSize: 64B"
}

div.p:
top_subtree_block.nodes -> bottom_subtrees.bs0: "Contiguous Jump [i*sizeof(Subtree)]" {
style: {
stroke: "#FF9800"
stroke-width: 4
animated: true
}
}
}

state_root: "ROOT SEARCH" {
shape: hexagon
style.fill: "#4CAF50"
style.font-color: white
label: "Step 1: Traverse Top\nIn-Cache (L1/L2)"
}

state_calc: "INDEX CALCULATE" {
shape: diamond
style.fill: "#FF9800"
style.font-color: white
label: "Step 2: Relative Offset\nTarget = Base + Offset"
}

state_leaf: "SUBTREE SEARCH" {
shape: hexagon
style.fill: "#4CAF50"
style.font-color: white
label: "Step 3: Access Bottom\n(Single Memory Load)"
}

state_root -> state_calc: "Exit Top Subtree"
state_calc -> state_leaf: "Memory Fetch"
}

l1_cache: "Metadata / Header" {
style.fill: "#E1BEE7"
style.stroke: "#9C27B0"
}
l2_cache: "Node Data Payload" {
style.fill: "#BBDEFB"
style.stroke: "#2196F3"
}
calc: "Address Math (ALU)" {
style.fill: "#FF9800"
shape: diamond
}
jump: "Contiguous Pointer" {
style: {
stroke: "#FF9800"
stroke-width: 3
}
}
}

ul.li:
TLB Efficiency: Related nodes reside on fewer physical 4KB pages.
| {
near: bottom-right
style: {
stroke: "#2196F3"
fill: "#E3F2FD"
border-radius: 5
}
}
